// Worked focus: http-ts-client-server-roles — Distinguish client, server, user agent, origin, intermediary, gateway, proxy, and cache roles per exchange. Demonstrate the result through TypeScript 7 strict types plus WHATWG Fetch Request, Response, Headers, URL, streams, and AbortSignal contracts.
function worked_http_ts_semantics_evidence_5(role: "client" | "server" | "proxy", status: number): { stage: string; accepted: boolean } {
  if (!Number.isInteger(status) || status < 100 || status > 599) {
    return { stage: "invalid status", accepted: false };
  }
  const stage = role === "proxy" ? "intermediary" : role;
  return { stage, accepted: status >= 200 && status < 400 };
}

